function escFm(s: string): string {
  return '"' + String(s).replace(/\\/g, '\\\\').replace(/"/g, '\\"') + '"';
}

function build(p: Person): string {
  const sources = [WIKI, ...(p.sources || [])];
  const seoTitle = `Is ${p.name} in the Epstein Files? — ${p.role}`;
  const seoDesc = `${p.name} (${p.role}) is named in connection with the Jeffrey Epstein files: ${p.context}`.slice(0, 300);
  const shortBio = `${p.name} — ${p.role} — is named in connection with the Jeffrey Epstein files. ${p.context} This profile is auto-generated from public reporting and is pending editorial review; inclusion does not imply guilt or wrongdoing.`;

  const fm: string[] = [];
  fm.push(`name: ${escFm(p.name)}`);
  fm.push(`seoTitle: ${escFm(seoTitle)}`);
  fm.push(`seoDescription: ${escFm(seoDesc)}`);
  if (p.aka && p.aka.length) {
    fm.push('aliases:');
    for (const a of p.aka) fm.push(`  - ${escFm(a)}`);
  } else {
    fm.push('aliases: []');
  }
  fm.push(`role: ${escFm(p.role)}`);
  fm.push(`category: ${p.category}`);
  fm.push(`shortBio: ${escFm(shortBio)}`);
  fm.push('notableConnections:');
  fm.push('  - jeffrey-epstein');
  fm.push('sources:');
  for (const s of sources) {
    fm.push(`  - title: ${escFm(s.title)}`);
    fm.push(`    url: ${escFm(s.url)}`);
  }
  fm.push('sensitive: false');
  fm.push('status: review');
  fm.push('autogenerated: true');

  // Answer-engine (AEO) Q&A body — phrased so search + chatbots quote it cleanly.
  const body = [
    `> **Auto-generated profile pending review.** This entry was compiled from public reporting because ${p.name} is named in connection with the Epstein files. It has not yet been editorially expanded.`,
    '',
    `## Is ${p.name} in the Epstein files?`,
    '',
    `Yes. ${p.name} (${p.role}) is named in connection with the Jeffrey Epstein files. ${p.context}`,
    '',
    `Being named in the files is **not** evidence of any crime or wrongdoing. People appear in these documents in many contexts — correspondence, flight logs, contact books, scheduling, photographs, or passing references. See the sources below for the specific, documented context, and the note at the bottom of this page.`,
    '',
  ].join('\n');

  return `---\n${fm.join('\n')}\n---\n\n${body}`;
}

function main() {
  // Dedup against existing by slug AND by name/alias
  const existingSlugs = new Set(readdirSync(PEOPLE_DIR).filter((f) => f.endsWith('.md')).map((f) => f.replace(/\.md$/, '')));
  const existingNames = new Set<string>();
  for (const f of readdirSync(PEOPLE_DIR).filter((f) => f.endsWith('.md'))) {
    const { frontmatter } = parseFrontmatter(readFileSync(join(PEOPLE_DIR, f), 'utf-8'));
    if (frontmatter.name) existingNames.add(String(frontmatter.name).toLowerCase());
    if (Array.isArray(frontmatter.aliases)) for (const a of frontmatter.aliases) existingNames.add(String(a).toLowerCase());
  }

  let created = 0;
  let skipped = 0;
  for (const p of PEOPLE) {
    const slug = slugify(p.name);
    if (existingSlugs.has(slug) || existingNames.has(p.name.toLowerCase())) {
      skipped++;
      console.log(`  SKIP (exists): ${p.name}`);
      continue;
    }
    const path = join(PEOPLE_DIR, `${slug}.md`);
    if (existsSync(path)) { skipped++; continue; }
    writeFileSync(path, build(p));
    created++;
    console.log(`  + ${slug} (${p.category})`);
  }
  console.log(`\nDone. Created ${created}, skipped ${skipped}. Total curated: ${PEOPLE.length}.`);
}

main();
